content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以給我一個袋子嗎？謝謝。",
      "pinyin": "Kěyǐ gěi wǒ yī gè dàizi ma? Xièxiè.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 ge4 dai4zi0 ma0? xie4xie4.",
      "translation_en": "Can you give me a bag? Thank you.",
      "translation_ko": "봉투 하나 주실 수 있나요? 감사합니다."
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, can you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "我想要一杯紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi hóngchá, bàn táng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2cha2, ban4 tang2, ke3yi3 ma0?",
      "translation_en": "I would like a cup of black tea, half sugar, okay?",
      "translation_ko": "홍차 한 잔, 반 당으로 주실 수 있나요?"
    },
    {
      "text": "可以給我一張衛生紙嗎？麻煩你。",
      "pinyin": "Kěyǐ gěi wǒ yī zhāng wèishēngzhǐ ma? Máfan nǐ.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 zhang1 wei4sheng1zhi3 ma0? ma2fan0 ni3.",
      "translation_en": "Can you give me a tissue? Please.",
      "translation_ko": "휴지 한 장 주실 수 있나요? 부탁드립니다."
    },
    {
      "text": "請問，這個價錢可以嗎？",
      "pinyin": "Qǐng wèn, zhège jiàqián kěyǐ ma?",
      "pinyin_numeric": "qing3 wen4, zhe4ge0 jia4qian2 ke3yi3 ma0?",
      "translation_en": "Excuse me, is this price okay?",
      "translation_ko": "실례합니다, 이 가격이 괜찮나요?"
    },
    {
      "text": "可以幫我外帶一杯綠茶嗎？謝謝。",
      "pinyin": "Kěyǐ bāng wǒ wàidài yī bēi lǜchá ma? Xièxiè.",
      "pinyin_numeric": "ke3yi3 bang1 wo3 wai4dai4 yi1 bei1 lü4cha2 ma0? xie4xie4.",
      "translation_en": "Can you help me get a green tea to go? Thank you.",
      "translation_ko": "녹차 한 잔 테이크아웃으로 부탁해도 될까요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次嗎？慢一點。",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma? Màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 ma0? man4 yi1 dian3.",
      "translation_en": "Excuse me, can you say it again? Slower.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 천천히요."
    },
    {
      "text": "可以給我一杯冰的豆漿嗎？不用加糖。",
      "pinyin": "Kěyǐ gěi wǒ yī bēi bīng de dòujiāng ma? Bùyòng jiā táng.",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 bei1 bing1 de0 dou4jiang1 ma0? bu4yong4 jia1 tang2.",
      "translation_en": "Can you give me a cup of iced soy milk? No sugar needed.",
      "translation_ko": "얀 두유 한 잔 주실 수 있나요? 설탕은 넣지 마세요."
    },
    {
      "text": "我想要內用，可以等一下嗎？",
      "pinyin": "Wǒ xiǎng yào nèiyòng, kěyǐ děng yīxià ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 nei4yong4, ke3yi3 deng3 yi1xia4 ma0?",
      "translation_en": "I want to eat in, can I wait a moment?",
      "translation_ko": "매장에서 먹고 싶은데, 잠시 기다려도 될까요?"
    }
  ]
}
